import "../src/app/styles/globals.css";

import { featureDisplay } from "@/shared/lib/fonts";
import { cn } from "@/shared/lib/ui/cn";
import { ToastListener, ToastProvider } from "@/shared/ui/notification";
import { ApiInterceptors } from "@/widgets/api-interceptors";
import type { Metadata } from "next";
import { DM_Sans, Inria_Serif, Inter, Roboto } from "next/font/google";
import type { FC, PropsWithChildren } from "react";
import { AllProviders } from "../src/app/providers";

const inriaSerif = Inria_Serif({
  subsets: ["latin"],
  weight: ["400", "700"],
  style: ["normal", "italic"],
  variable: "--font-serif",
});

const inter = Inter({
  subsets: ["latin"],
  weight: ["400", "600"],
  variable: "--font-sans",
});

const roboto = Roboto({
  subsets: ["latin"],
  weight: ["400", "500", "700"],
  variable: "--font-roboto",
});

// REDESIGN: Add new Fonts
const dmSans = DM_Sans({
  subsets: ["latin"],
  weight: ["400", "500", "700"],
  variable: "--font-dm-sans",
});

export const metadata: Metadata = {
  title: "Luxury Asset Liquidity",
  description: "Luxury Asset Liquidity",
  manifest: "/site.webmanifest",
  icons: [
    {
      sizes: "32x32",
      href: "/favicon-32x32.png",
      url: "/favicon-32x32.png",
    },
    {
      sizes: "16x16",
      href: "/favicon-16x16.png",
      url: "/favicon-16x16.png",
    },
    {
      rel: "apple-touch-icon",
      href: "/apple-touch-icon.png",
      url: "/favicon-16x16.png",
      sizes: "180x180",
    },
  ],
};

const RootLayout: FC<PropsWithChildren> = ({ children }) => (
  <html lang="en">
    <body
      className={cn(
        dmSans.variable,
        featureDisplay.variable,
        inriaSerif.variable,
        inter.variable,
        roboto.variable,
        "h-full min-h-full font-new-sans"
      )}
    >
      <ToastProvider>
        <AllProviders>
          {children}
          <ApiInterceptors />
        </AllProviders>
        <ToastListener />
      </ToastProvider>
    </body>
  </html>
);

export default RootLayout;

